package com.interview.incidentrca.service;
import com.interview.incidentrca.dto.*;import com.interview.incidentrca.entity.*;import com.interview.incidentrca.enums.*;import com.interview.incidentrca.exception.*;import com.interview.incidentrca.mapper.IncidentMapper;import com.interview.incidentrca.repository.*;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.util.*;import java.util.stream.*;
@Service @RequiredArgsConstructor public class IncidentService{private final IncidentRepository incidents;private final ServiceComponentRepository services;private final UserRepository users;private final IncidentCommentRepository comments;private final IncidentStatusHistoryRepository histories;private final IncidentMapper mapper;private final SlaService sla;private final DuplicateDetectionService dupes;private final AuditService audit;private final CurrentUserService current;private final RootCauseService rootCause;
 @Transactional public IncidentResponse create(IncidentCreateRequest r){User actor=current.user();ServiceComponent svc=services.findByNameIgnoreCase(r.serviceName()).orElseGet(()->services.save(ServiceComponent.builder().name(r.serviceName()).ownerTeam("Platform Operations").businessCriticality("HIGH").createdAt(Instant.now()).build()));User assignee=r.assignedEngineerId()==null?null:users.findById(r.assignedEngineerId()).orElseThrow(()->new ResourceNotFoundException("Engineer not found"));Incident i=incidents.save(Incident.builder().title(r.title()).description(r.description()).severity(r.severity()).status(IncidentStatus.OPEN).serviceComponent(svc).assignedEngineer(assignee).createdBy(actor).createdAt(Instant.now()).updatedAt(Instant.now()).build());histories.save(IncidentStatusHistory.builder().incident(i).toStatus(IncidentStatus.OPEN).changedBy(actor).note("Incident created").changedAt(Instant.now()).build());audit.record(actor,"INCIDENT_CREATED","Created incident #"+i.getId());return response(i);} 
 @Transactional(readOnly=true) public Page<IncidentResponse> search(IncidentStatus status,Severity severity,String service,Long engineerId,Instant from,Instant to,Pageable p){return incidents.search(status,severity,service==null?"":service,engineerId,from,to,p).map(this::response);} @Transactional(readOnly=true) public Incident getEntity(Long id){return incidents.findById(id).orElseThrow(()->new ResourceNotFoundException("Incident not found"));} @Transactional(readOnly=true) public IncidentResponse get(Long id){return response(getEntity(id));}
 @Transactional public IncidentResponse update(Long id,IncidentUpdateRequest r){Incident i=getEntity(id);ServiceComponent svc=services.findByNameIgnoreCase(r.serviceName()).orElseGet(()->services.save(ServiceComponent.builder().name(r.serviceName()).ownerTeam("Platform Operations").businessCriticality("MEDIUM").createdAt(Instant.now()).build()));i.setTitle(r.title());i.setDescription(r.description());i.setSeverity(r.severity());i.setServiceComponent(svc);i.setUpdatedAt(Instant.now());audit.record(current.user(),"INCIDENT_UPDATED","Updated incident #"+id);return response(incidents.save(i));}
 @Transactional public IncidentResponse changeStatus(Long id,StatusUpdateRequest r){Incident i=getEntity(id);User actor=current.user();IncidentStatus old=i.getStatus();i.setStatus(r.status());i.setUpdatedAt(Instant.now());if(r.status()==IncidentStatus.RESOLVED||r.status()==IncidentStatus.CLOSED)i.setResolvedAt(Instant.now());histories.save(IncidentStatusHistory.builder().incident(i).fromStatus(old).toStatus(r.status()).changedBy(actor).note(r.note()).changedAt(Instant.now()).build());audit.record(actor,"STATUS_CHANGED","Incident #"+id+" changed from "+old+" to "+r.status());return response(incidents.save(i));}
 @Transactional public IncidentResponse assign(Long id,AssignRequest r){Incident i=getEntity(id);User engineer=users.findById(r.engineerId()).orElseThrow(()->new ResourceNotFoundException("Engineer not found"));if(engineer.getRole()!=Role.ENGINEER&&engineer.getRole()!=Role.ADMIN)throw new BadRequestException("Assignee must be ENGINEER or ADMIN");i.setAssignedEngineer(engineer);i.setUpdatedAt(Instant.now());audit.record(current.user(),"INCIDENT_ASSIGNED","Incident #"+id+" assigned to "+engineer.getEmail());return response(incidents.save(i));}
 @Transactional public void delete(Long id){Incident i=getEntity(id);incidents.delete(i);audit.record(current.user(),"INCIDENT_DELETED","Deleted incident #"+id);} @Transactional public TimelineEventResponse comment(Long id,CommentRequest r){Incident i=getEntity(id);User actor=current.user();IncidentComment c=comments.save(IncidentComment.builder().incident(i).author(actor).message(r.message()).createdAt(Instant.now()).build());audit.record(actor,"COMMENT_ADDED","Comment added to incident #"+id);return new TimelineEventResponse("COMMENT_ADDED",actor.getName(),c.getMessage(),c.getCreatedAt());}
 @Transactional(readOnly=true) public List<TimelineEventResponse> timeline(Long id){Incident i=getEntity(id);List<TimelineEventResponse> events=new ArrayList<>();events.add(new TimelineEventResponse("CREATED",i.getCreatedBy().getName(),"Incident created",i.getCreatedAt()));if(i.getAssignedEngineer()!=null)events.add(new TimelineEventResponse("ASSIGNED",i.getAssignedEngineer().getName(),"Currently assigned engineer",i.getUpdatedAt()));histories.findByIncidentIdOrderByChangedAtAsc(id).forEach(h->events.add(new TimelineEventResponse("STATUS_CHANGED",h.getChangedBy().getName(),"Status changed to "+h.getToStatus()+(h.getNote()==null?"":" - "+h.getNote()),h.getChangedAt())));comments.findByIncidentIdOrderByCreatedAtAsc(id).forEach(c->events.add(new TimelineEventResponse("COMMENT_ADDED",c.getAuthor().getName(),c.getMessage(),c.getCreatedAt())));return events.stream().sorted(Comparator.comparing(TimelineEventResponse::timestamp)).toList();}
 public List<RootCauseSuggestionResponse> suggestions(Long id){return rootCause.suggest(getEntity(id));} @Transactional(readOnly=true) public List<DuplicateIncidentResponse> duplicates(Long id){return dupes.findDuplicates(getEntity(id));} private IncidentResponse response(Incident i){return mapper.toIncident(i,sla.state(i),dupes.findDuplicates(i).stream().map(DuplicateIncidentResponse::incidentId).toList());}}
